from typing import List, Optional

def int_to_string(number: int, alphabet: List[str], padding: Optional[int] = None) -> str:
    """
    将一个数字使用给定的字母表转换为字符串。

      数字表示一个短的 UUID。

      输出的字符串以最高有效位（Most Significant Digit）优先。

      @param number: 整型值  
      @param alphabet: 包含字母的列表  
      @param padding: 可选参数，整型值，用于指定填充长度  
      @return: 与整型值对应的字符串值
    将一个数字转换为字符串，使用给定的字母表。

    输出的字符串以最高有效位优先。
    """
    base = len(alphabet)
    result = []

    if number == 0:
        result.append(alphabet[0])

    while number > 0:
        result.append(alphabet[number % base])
        number //= base

    result.reverse()

    if padding is not None:
        result = ([''] * (padding - len(result))) + result

    return ''.join(result)

def load_configurations(config_filenames, overrides=None, resolve_env=True):
    import logging
    import os
    import json

    logger = logging.getLogger(__name__)
    error_records = []
    config_dict = {}

    for filename in config_filenames:
        try:
            if not os.access(filename, os.R_OK):
                raise PermissionError(f"Permission denied: {filename}")

            with open(filename, 'r') as file:
                config = json.load(file)

            if overrides:
                config.update(overrides)

            if resolve_env:
                for key, value in config.items():
                    if isinstance(value, str) and value.startswith('$'):
                        env_var = value[1:]
                        config[key] = os.getenv(env_var, value)

            config_dict[filename] = config

        except Exception as e:
            log_record = logger.error(f"Error loading configuration from {filename}: {e}", exc_info=True)
            error_records.append(log_record)

    return config_dict, error_records

