def determineMetaclass(bases, explicit_mc=None):
    """
    从一个或多个基类以及可选的显式 __metaclass__ 中确定元类。
    """
    if explicit_mc is not None:
        return explicit_mc

    metaclasses = [type(base) for base in bases]
    if not metaclasses:
        return type

    # 取所有元类的交集
    metaclass = metaclasses[0]
    for mc in metaclasses[1:]:
        if not issubclass(mc, metaclass):
            metaclass = type('CombinedMeta', (metaclass, mc), {})

    return metaclass

def pop(self, key, default=__marker):
    """
    `D.pop(k[, d]) -> v`：移除指定的键并返回对应的值。  
    如果未找到指定的键，则返回 `d`（如果提供了 `d`）；否则会引发 `KeyError` 异常。
    """
    if key in self:
        value = self[key]
        del self[key]
        return value
    elif default is not self.__marker:
        return default
    else:
        raise KeyError(f'Key {key} not found.')

